// Combine all scraped data into a single research package
// In production, add a proper HTML parser library or use cheerio via Code node

const etsyData = $('🔍 Scrape Etsy Trending').first().json;
const gumroadData = $('🔍 Scrape Gumroad Trending').first().json;
const cfData = $('🔍 Scrape Creative Fabrica').first().json;
const trendsData = $('📈 Google Trends API').first().json;

// Build research summary for Ollama to analyze
const researchPackage = {
  timestamp: new Date().toISOString(),
  week: `Week of ${new Date().toLocaleDateString('en-US', {month:'long', day:'numeric', year:'numeric'})}`,
  sources: {
    etsy: {
      url: 'https://www.etsy.com/search?q=digital+download&order=most_relevant',
      status: etsyData ? 'fetched' : 'failed',
      contentLength: etsyData?.body?.length || 0
    },
    gumroad: {
      url: 'https://gumroad.com/discover?sort=featured&tags=digital',
      status: gumroadData ? 'fetched' : 'failed',
      contentLength: gumroadData?.body?.length || 0
    },
    creativeFabrica: {
      url: 'https://www.creativefabrica.com/freebies/?orderby=popular',
      status: cfData ? 'fetched' : 'failed',
      contentLength: cfData?.body?.length || 0
    },
    googleTrends: {
      status: trendsData ? 'fetched' : 'failed'
    }
  },
  // Seed keywords for Ollama to build on - expanded weekly by AI
  trendingCategories: [
    'printable wall art',
    'notion template productivity',
    'ai generated coloring pages',
    'resume template canva',
    'budget planner printable',
    'social media template pack',
    'ebook minimalist journal',
    'digital planner ipad',
    'affirmation card printable',
    'logo design bundle'
  ],
  productTypes: ['Printables/Templates', 'AI Art/Images', 'eBooks/Guides', 'Notion/Canva Templates'],
  freeAiTools: [
    'Canva Free (templates, graphics)',
    'Adobe Express Free (design)',
    'DALL-E via ChatGPT Free (AI images)',
    'Leonardo.ai Free (AI art)',
    'Stable Diffusion (local/free)',
    'Gamma.app Free (ebooks/presentations)',
    'Notion Free (templates)',
    'Google Docs (ebooks)',
    'Ollama Local (text generation)'
  ]
};

return [{ json: researchPackage }];

// Parse Ollama's JSON response safely
const rawResponse = $input.first().json;

let parsed;
try {
  // Ollama returns message.content
  const content = rawResponse?.message?.content || rawResponse?.response || '';

  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/) || 
                    content.match(/({[\s\S]*})/);

  const jsonStr = jsonMatch ? jsonMatch[1] || jsonMatch[0] : content;
  parsed = JSON.parse(jsonStr.trim());
} catch(e) {
  // Fallback structure if parsing fails
  parsed = {
    research_week: new Date().toLocaleDateString(),
    market_insights: 'Unable to parse AI response - please check Ollama connection',
    top_opportunities: []
  };
}

// Add metadata
parsed.generated_at = new Date().toISOString();
parsed.status = 'pending_approval';
parsed.workflow_version = '1.0';

return [{ json: parsed }];

// Flatten opportunities into individual rows for Google Sheets
const research = $input.first().json;
const rows = [];

if (research.top_opportunities && research.top_opportunities.length > 0) {
  for (const opp of research.top_opportunities) {
    rows.push({
      json: {
        // Sheet columns
        Week: research.research_week || new Date().toLocaleDateString(),
        Rank: opp.rank,
        Product_Name: opp.product_name,
        Category: opp.category,
        Trend_Score: opp.trend_score,
        Recreatability_Score: opp.recreatability_score,
        Price_Min: opp.estimated_price_min,
        Price_Max: opp.estimated_price_max,
        Creation_Tool: opp.creation_tool,
        Creation_Hours: opp.creation_time_hours,
        Target_Keyword: opp.target_keyword,
        Description: opp.description,
        Creation_Steps: (opp.creation_steps || []).join(' | '),
        Market_Insights: research.market_insights,
        // Approval columns
        APPROVED: 'PENDING',
        Notes: '',
        Date_Added: new Date().toISOString(),
        Status: 'Research Complete'
      }
    });
  }
} else {
  rows.push({
    json: {
      Week: new Date().toLocaleDateString(),
      Rank: 0,
      Product_Name: 'ERROR - No opportunities found',
      Status: 'Failed',
      Date_Added: new Date().toISOString()
    }
  });
}

return rows;

// Generate a human-readable summary for logging
const allRows = $input.all();
const summary = {
  json: {
    event: 'RESEARCH_COMPLETE',
    timestamp: new Date().toISOString(),
    products_found: allRows.length,
    next_step: 'Go to Google Sheets > Research_Opportunities tab > Change APPROVED column to YES for products you want to create',
    sheet_action_required: true,
    message: `✅ Research complete! ${allRows.length} product opportunities written to Google Sheets. Open your sheet and mark APPROVED = YES for products to proceed to creation.`
  }
};
return [summary];
